296: // EmailMatchingInterceptor is a grpc.UnaryServerInterceptor only used in the case where the user is using OIDC
297: // and wants to whitelist a group of users issuing operations against the Flipt server.
298: func EmailMatchingInterceptor(logger *zap.Logger, rgxs []*regexp.Regexp, o ...containers.Option[InterceptorOptions]) grpc.UnaryServerInterceptor {
299: 	var opts InterceptorOptions
300: 	containers.ApplyAll(&opts, o...)
301: 
302: 	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
303: 		// skip auth for any preconfigured servers
304: 		if skipped(ctx, info.Server, opts) {
305: 			logger.Debug("skipping authentication for server", zap.String("method", info.FullMethod))
306: 			return handler(ctx, req)
307: 		}
308: 
309: 		auth := GetAuthenticationFrom(ctx)
310: 		if auth == nil {
311: 			panic("authentication not found in context, middleware installed incorrectly")
312: 		}
313: 
314: 		// this mechanism only applies to authentications created using OIDC
315: 		if auth.Method != authrpc.Method_METHOD_OIDC {
316: 			return handler(ctx, req)
317: 		}
318: 
319: 		email, ok := auth.Metadata["io.flipt.auth.oidc.email"]
320: 		if !ok {
321: 			logger.Debug("no email provided but required for auth")
322: 			return ctx, ErrUnauthenticated
323: 		}
324: 
325: 		matched := false
326: 
327: 		for _, rgx := range rgxs {
328: 			if matched = rgx.MatchString(email); matched {
329: 				break
330: 			}
331: 		}
332: 
333: 		if !matched {
334: 			logger.Error("unauthenticated", zap.String("reason", "email is not allowed"))
335: 			return ctx, ErrUnauthenticated
336: 		}
337: 
338: 		return handler(ctx, req)
339: 	}
340: }
