			t.Logf("REGRESSION: ForwardCookies set 'flipt_client_token' metadata key instead of 'grpcgateway-cookie'")
			t.Logf("  This is the wrong format for the gRPC middleware to parse")
		}
		if len(stateKey) > 0 {
			t.Logf("Note: 'flipt_client_state' metadata was also set: %v", stateKey)
		}
	})
}

// testServerSkipAuthenticationMechanism verifies that the server skip
// authentication mechanism exists and works correctly.
func testServerSkipAuthenticationMechanism(t *testing.T) {
	var (
		logger   = zaptest.NewLogger(t)
		store    = memory.NewStore()
		listener = bufconn.Listen(1024 * 1024)
	)

	// Create two servers: one that skips auth, one that requires it
	skipAuthServer := grpc.NewServer(
		grpc.ChainUnaryInterceptor(
			authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, store),
			middlewaregrpc.ErrorUnaryInterceptor,
		),
	)

	requireAuthServer := grpc.NewServer(
		grpc.ChainUnaryInterceptor(
			authmiddlewaregrpc.AuthenticationRequiredInterceptor(logger),
			authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, store),
			middlewaregrpc.ErrorUnaryInterceptor,
		),
	)

	defer skipAuthServer.Stop()
	defer requireAuthServer.Stop()

	// Register authentication service on both servers
	rpcauth.RegisterAuthenticationServiceServer(skipAuthServer, authn.NewServer(logger, store))
	rpcauth.RegisterAuthenticationServiceServer(requireAuthServer, authn.NewServer(logger, store))

	errC := make(chan error)
	go func() {
		errC <- skipAuthServer.Serve(listener)
	}()

	var (
		ctx    = context.Background()
		dialer = func(context.Context, string) (net.Conn, error) {
			return listener.Dial()
		}
	)

	// Create a valid client token
	clientToken, _, err := store.CreateAuthentication(ctx, &storageauth.CreateAuthenticationRequest{
		Method:    rpcauth.Method_METHOD_TOKEN,
		ExpiresAt: timestamppb.New(time.Now().Add(time.Hour).UTC()),
	})
	require.NoError(t, err)

	conn, err := grpc.DialContext(ctx, "", grpc.WithInsecure(), grpc.WithContextDialer(dialer))
	require.NoError(t, err)
	defer conn.Close()

	client := rpcauth.NewAuthenticationServiceClient(conn)

	t.Run("ServerWithoutAuthSkipMechanism", func(t *testing.T) {
		// Without proper authentication, this should fail
		_, err := client.GetAuthenticationSelf(ctx, &emptypb.Empty{})
		assert.ErrorIs(t, err, status.Error(codes.Unauthenticated, "request was not authenticated"),
			"request without authentication should be rejected")
	})

	t.Run("ServerCanImplementSkipsAuthenticationInterface", func(t *testing.T) {
		// Verify that servers can implement the SkipsAuthenticationServer interface
		authServer := authn.NewServer(logger, store)

		// Check if the authentication server implements SkipsAuthentication
		skipAuthSrv, ok := interface{}(authServer).(authmiddlewaregrpc.SkipsAuthenticationServer)
		if ok {
			result := skipAuthSrv.SkipsAuthentication(ctx)
			t.Logf("AuthenticationServer implements SkipsAuthenticationServer: %v", result)
		} else {
			t.Logf("AuthenticationServer does NOT implement SkipsAuthenticationServer interface")
			t.Log("This means authentication cannot be skipped for this server unless explicitly configured")
		}
	})

	t.Run("ServerSkipAuthenticationViaOption", func(t *testing.T) {
		// Test that WithServerSkipsAuthentication option exists and can be used
		// This verifies that the mechanism for skipping auth is available
		mockServer := &mockAuthServer{skipsAuth: true}

		interceptor := authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(
			logger,
			store,
			authmiddlewaregrpc.WithServerSkipsAuthentication(mockServer),
		)

		// Create a context without any authentication
		unauthCtx := context.Background()

		var retrievedCtx context.Context
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			retrievedCtx = ctx
			return nil, nil
		}

		// Call the interceptor with the mock server
		_, err := interceptor(
			unauthCtx,
			nil,
			&grpc.UnaryServerInfo{
				Server: mockServer,
			},
			handler,
		)

		// With the server registered in WithServerSkipsAuthentication,
		// the request should pass through even without authentication
		assert.NoError(t, err, "server registered with WithServerSkipsAuthentication should allow unauthenticated requests")
	})

	if err := <-errC; err != nil {
		t.Fatal(err)
	}
}

// mockAuthServer is a mock gRPC server that implements SkipsAuthenticationServer
type mockAuthServer struct {
	skipsAuth bool
}

func (m *mockAuthServer) SkipsAuthentication(ctx context.Context) bool {
	return m.skipsAuth
}

