// TestRegression tests the two main authentication issues:
// 1. Cookie-based token extraction fails
// 2. Server-level authentication bypass mechanism
func TestRegression(t *testing.T) {
	t.Run("CookieBasedTokenExtraction", testCookieBasedTokenExtraction)
	t.Run("ServerSkipAuthenticationMechanism", testServerSkipAuthenticationMechanism)
}

// testCookieBasedTokenExtraction demonstrates that cookie-based tokens
// are not properly extracted and forwarded through the HTTP gateway to gRPC.
func testCookieBasedTokenExtraction(t *testing.T) {
	var (
		logger   = zaptest.NewLogger(t)
		store    = memory.NewStore()
		listener = bufconn.Listen(1024 * 1024)
		server   = grpc.NewServer(
			grpc.ChainUnaryInterceptor(
				authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, store),
				middlewaregrpc.ErrorUnaryInterceptor,
			),
		)
		errC     = make(chan error)
		shutdown = func(t *testing.T) {
			t.Helper()
			server.Stop()
			if err := <-errC; err != nil {
				t.Fatal(err)
			}
		}
	)

	defer shutdown(t)

	rpcauth.RegisterAuthenticationServiceServer(server, authn.NewServer(logger, store))

	go func() {
		errC <- server.Serve(listener)
	}()

	var (
		ctx    = context.Background()
		dialer = func(context.Context, string) (net.Conn, error) {
			return listener.Dial()
		}
	)

	// Create a valid client token
	clientToken, _, err := store.CreateAuthentication(ctx, &storageauth.CreateAuthenticationRequest{
		Method:    rpcauth.Method_METHOD_TOKEN,
		ExpiresAt: timestamppb.New(time.Now().Add(time.Hour).UTC()),
	})
	require.NoError(t, err)

	conn, err := grpc.DialContext(ctx, "", grpc.WithInsecure(), grpc.WithContextDialer(dialer))
	require.NoError(t, err)
	defer conn.Close()

	client := rpcauth.NewAuthenticationServiceClient(conn)

	t.Run("TokenInAuthorizationHeader", func(t *testing.T) {
		// This test should PASS - tokens in Authorization header work
		authorizedCtx := metadata.AppendToOutgoingContext(
			ctx,
			"authorization",
			"Bearer "+clientToken,
		)
		_, err := client.GetAuthenticationSelf(authorizedCtx, &emptypb.Empty{})
		assert.NoError(t, err, "token in Authorization header should work")
	})

	t.Run("TokenInCookieViaMetadata", func(t *testing.T) {
		// This test demonstrates the cookie extraction works at the gRPC level
		// when metadata is properly set. This is what SHOULD happen if ForwardCookies worked correctly.
		cookieCtx := metadata.AppendToOutgoingContext(
			ctx,
			"grpcgateway-cookie",
			fmt.Sprintf("%s=%s", middlewarecommon.TokenCookieKey, clientToken),
		)
		_, err := client.GetAuthenticationSelf(cookieCtx, &emptypb.Empty{})
		assert.NoError(t, err, "token in grpcgateway-cookie metadata should work at gRPC level")
	})

	t.Run("ForwardCookiesFunction", func(t *testing.T) {
		// This test directly tests the ForwardCookies function to show
		// that it doesn't properly convert HTTP cookies to gRPC metadata.
		httpReq, err := http.NewRequest("GET", "http://localhost:8080/", nil)
		require.NoError(t, err)

		// Set a valid client token in an HTTP cookie
		httpReq.AddCookie(&http.Cookie{
			Name:  middlewarecommon.TokenCookieKey,
			Value: clientToken,
		})

		// Call ForwardCookies to convert the HTTP request to gRPC metadata
		md := method.ForwardCookies(ctx, httpReq)

		// The bug: ForwardCookies doesn't properly populate the "grpcgateway-cookie" metadata
		// that the gRPC middleware expects.

		// Check if the metadata has the expected key
		grpcgatewayCookie := md.Get("grpcgateway-cookie")
		if len(grpcgatewayCookie) == 0 {
			// This is the actual bug we're testing for
			t.Error("REGRESSION: ForwardCookies failed to set 'grpcgateway-cookie' metadata key")
			t.Log("The ForwardCookies function doesn't properly extract HTTP cookies and forward them as gRPC metadata")
		} else {
			// If cookies are being properly forwarded, they should be in the HTTP Cookie header format
			expectedValue := fmt.Sprintf("%s=%s", middlewarecommon.TokenCookieKey, clientToken)
			assert.Equal(t, expectedValue, grpcgatewayCookie[0],
				"grpcgateway-cookie should contain the token in 'name=value' format")
		}

		// Check the incorrect keys that are actually being set (due to the bug)
