package main

import (
	"context"
	"fmt"
	"net"
	"net/http"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"go.flipt.io/flipt/internal/server/authn"
	authmiddlewaregrpc "go.flipt.io/flipt/internal/server/authn/middleware/grpc"
	middlewarecommon "go.flipt.io/flipt/internal/server/authn/middleware/common"
	"go.flipt.io/flipt/internal/server/authn/method"
	middlewarehttp "go.flipt.io/flipt/internal/server/authn/middleware/http"
	middlewaregrpc "go.flipt.io/flipt/internal/server/middleware/grpc"
	storageauth "go.flipt.io/flipt/internal/storage/authn"
	"go.flipt.io/flipt/internal/storage/authn/memory"
	rpcauth "go.flipt.io/flipt/rpc/flipt/auth"
	"go.uber.org/zap/zaptest"
	"google.golang.org/grpc"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/metadata"
	"google.golang.org/grpc/status"
	"google.golang.org/grpc/test/bufconn"
	"google.golang.org/protobuf/types/known/emptypb"
	"google.golang.org/protobuf/types/known/timestamppb"
)

// TestRegression tests the two main authentication issues:
// 1. Cookie-based token extraction fails
// 2. Server-level authentication bypass mechanism
func TestRegression(t *testing.T) {
	t.Run("CookieBasedTokenExtraction", testCookieBasedTokenExtraction)
	t.Run("ServerSkipAuthenticationMechanism", testServerSkipAuthenticationMechanism)
}

// testCookieBasedTokenExtraction demonstrates that cookie-based tokens
// are not properly extracted and forwarded through the HTTP gateway to gRPC.
func testCookieBasedTokenExtraction(t *testing.T) {
	var (
		logger   = zaptest.NewLogger(t)
		store    = memory.NewStore()
		listener = bufconn.Listen(1024 * 1024)
		server   = grpc.NewServer(
			grpc.ChainUnaryInterceptor(
				authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, store),
				middlewaregrpc.ErrorUnaryInterceptor,
			),
		)
		errC     = make(chan error)
		shutdown = func(t *testing.T) {
			t.Helper()
			server.Stop()
			if err := <-errC; err != nil {
				t.Fatal(err)
			}
		}
	)

	defer shutdown(t)

	rpcauth.RegisterAuthenticationServiceServer(server, authn.NewServer(logger, store))

	go func() {
		errC <- server.Serve(listener)
	}()

	var (
		ctx    = context.Background()
		dialer = func(context.Context, string) (net.Conn, error) {
			return listener.Dial()
		}
	)

	// Create a valid client token
	clientToken, _, err := store.CreateAuthentication(ctx, &storageauth.CreateAuthenticationRequest{
		Method:    rpcauth.Method_METHOD_TOKEN,
		ExpiresAt: timestamppb.New(time.Now().Add(time.Hour).UTC()),
	})
	require.NoError(t, err)

	conn, err := grpc.DialContext(ctx, "", grpc.WithInsecure(), grpc.WithContextDialer(dialer))
	require.NoError(t, err)
	defer conn.Close()

	client := rpcauth.NewAuthenticationServiceClient(conn)

	t.Run("TokenInAuthorizationHeader", func(t *testing.T) {
		// This test should PASS - tokens in Authorization header work
		authorizedCtx := metadata.AppendToOutgoingContext(
			ctx,
			"authorization",
			"Bearer "+clientToken,
		)
		_, err := client.GetAuthenticationSelf(authorizedCtx, &emptypb.Empty{})
		assert.NoError(t, err, "token in Authorization header should work")
	})

	t.Run("TokenInCookieViaMetadata", func(t *testing.T) {
		// This test demonstrates the cookie extraction works at the gRPC level
		// when metadata is properly set. This is what SHOULD happen if ForwardCookies worked correctly.
		cookieCtx := metadata.AppendToOutgoingContext(
			ctx,
			"grpcgateway-cookie",
			fmt.Sprintf("%s=%s", middlewarecommon.TokenCookieKey, clientToken),
		)
		_, err := client.GetAuthenticationSelf(cookieCtx, &emptypb.Empty{})
		assert.NoError(t, err, "token in grpcgateway-cookie metadata should work at gRPC level")
	})

	t.Run("ForwardCookiesFunction", func(t *testing.T) {
		// This test directly tests the ForwardCookies function to show
		// that it doesn't properly convert HTTP cookies to gRPC metadata.
		httpReq, err := http.NewRequest("GET", "http://localhost:8080/", nil)
		require.NoError(t, err)

		// Set a valid client token in an HTTP cookie
		httpReq.AddCookie(&http.Cookie{
			Name:  middlewarecommon.TokenCookieKey,
			Value: clientToken,
		})

		// Call ForwardCookies to convert the HTTP request to gRPC metadata
		md := method.ForwardCookies(ctx, httpReq)

		// The bug: ForwardCookies doesn't properly populate the "grpcgateway-cookie" metadata
		// that the gRPC middleware expects.

		// Check if the metadata has the expected key
		grpcgatewayCookie := md.Get("grpcgateway-cookie")
		if len(grpcgatewayCookie) == 0 {
			// This is the actual bug we're testing for
			t.Error("REGRESSION: ForwardCookies failed to set 'grpcgateway-cookie' metadata key")
			t.Log("The ForwardCookies function doesn't properly extract HTTP cookies and forward them as gRPC metadata")
		} else {
			// If cookies are being properly forwarded, they should be in the HTTP Cookie header format
			expectedValue := fmt.Sprintf("%s=%s", middlewarecommon.TokenCookieKey, clientToken)
			assert.Equal(t, expectedValue, grpcgatewayCookie[0],
				"grpcgateway-cookie should contain the token in 'name=value' format")
		}

		// Check the incorrect keys that are actually being set (due to the bug)
		stateKey := md.Get("flipt_client_state")
		tokenKey := md.Get("flipt_client_token")
		if len(tokenKey) > 0 {
			t.Logf("REGRESSION: ForwardCookies set 'flipt_client_token' metadata key instead of 'grpcgateway-cookie'")
			t.Logf("  This is the wrong format for the gRPC middleware to parse")
		}
		if len(stateKey) > 0 {
			t.Logf("Note: 'flipt_client_state' metadata was also set: %v", stateKey)
		}
	})
}

// testServerSkipAuthenticationMechanism verifies that the server skip
// authentication mechanism exists and works correctly.
func testServerSkipAuthenticationMechanism(t *testing.T) {
	var (
		logger   = zaptest.NewLogger(t)
		store    = memory.NewStore()
		listener = bufconn.Listen(1024 * 1024)
	)

	// Create two servers: one that skips auth, one that requires it
	skipAuthServer := grpc.NewServer(
		grpc.ChainUnaryInterceptor(
			authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, store),
			middlewaregrpc.ErrorUnaryInterceptor,
		),
	)

	requireAuthServer := grpc.NewServer(
		grpc.ChainUnaryInterceptor(
			authmiddlewaregrpc.AuthenticationRequiredInterceptor(logger),
			authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(logger, store),
			middlewaregrpc.ErrorUnaryInterceptor,
		),
	)

	defer skipAuthServer.Stop()
	defer requireAuthServer.Stop()

	// Register authentication service on both servers
	rpcauth.RegisterAuthenticationServiceServer(skipAuthServer, authn.NewServer(logger, store))
	rpcauth.RegisterAuthenticationServiceServer(requireAuthServer, authn.NewServer(logger, store))

	errC := make(chan error)
	go func() {
		errC <- skipAuthServer.Serve(listener)
	}()

	var (
		ctx    = context.Background()
		dialer = func(context.Context, string) (net.Conn, error) {
			return listener.Dial()
		}
	)

	// Create a valid client token
	clientToken, _, err := store.CreateAuthentication(ctx, &storageauth.CreateAuthenticationRequest{
		Method:    rpcauth.Method_METHOD_TOKEN,
		ExpiresAt: timestamppb.New(time.Now().Add(time.Hour).UTC()),
	})
	require.NoError(t, err)

	conn, err := grpc.DialContext(ctx, "", grpc.WithInsecure(), grpc.WithContextDialer(dialer))
	require.NoError(t, err)
	defer conn.Close()

	client := rpcauth.NewAuthenticationServiceClient(conn)

	t.Run("ServerWithoutAuthSkipMechanism", func(t *testing.T) {
		// Without proper authentication, this should fail
		_, err := client.GetAuthenticationSelf(ctx, &emptypb.Empty{})
		assert.ErrorIs(t, err, status.Error(codes.Unauthenticated, "request was not authenticated"),
			"request without authentication should be rejected")
	})

	t.Run("ServerCanImplementSkipsAuthenticationInterface", func(t *testing.T) {
		// Verify that servers can implement the SkipsAuthenticationServer interface
		authServer := authn.NewServer(logger, store)

		// Check if the authentication server implements SkipsAuthentication
		skipAuthSrv, ok := interface{}(authServer).(authmiddlewaregrpc.SkipsAuthenticationServer)
		if ok {
			result := skipAuthSrv.SkipsAuthentication(ctx)
			t.Logf("AuthenticationServer implements SkipsAuthenticationServer: %v", result)
		} else {
			t.Logf("AuthenticationServer does NOT implement SkipsAuthenticationServer interface")
			t.Log("This means authentication cannot be skipped for this server unless explicitly configured")
		}
	})

	t.Run("ServerSkipAuthenticationViaOption", func(t *testing.T) {
		// Test that WithServerSkipsAuthentication option exists and can be used
		// This verifies that the mechanism for skipping auth is available
		mockServer := &mockAuthServer{skipsAuth: true}

		interceptor := authmiddlewaregrpc.ClientTokenAuthenticationInterceptor(
			logger,
			store,
			authmiddlewaregrpc.WithServerSkipsAuthentication(mockServer),
		)

		// Create a context without any authentication
		unauthCtx := context.Background()

		var retrievedCtx context.Context
		handler := func(ctx context.Context, req interface{}) (interface{}, error) {
			retrievedCtx = ctx
			return nil, nil
		}

		// Call the interceptor with the mock server
		_, err := interceptor(
			unauthCtx,
			nil,
			&grpc.UnaryServerInfo{
				Server: mockServer,
			},
			handler,
		)

		// With the server registered in WithServerSkipsAuthentication,
		// the request should pass through even without authentication
		assert.NoError(t, err, "server registered with WithServerSkipsAuthentication should allow unauthenticated requests")
	})

	if err := <-errC; err != nil {
		t.Fatal(err)
	}
}

// mockAuthServer is a mock gRPC server that implements SkipsAuthenticationServer
type mockAuthServer struct {
	skipsAuth bool
}

func (m *mockAuthServer) SkipsAuthentication(ctx context.Context) bool {
	return m.skipsAuth
}

